/**
 * migrate-css-postbuild.js
 * Programmatically sweeps all HTML files generated by the build pipeline
 * and migrates static inline styles to CSS classes.
 * Dynamically reuses existing classes from autogenerated-utility.css and
 * registers any new inline styles encountered on-the-fly.
 */
const fs = require('fs');
const path = require('path');

const BASE = path.resolve(__dirname, '..');
const UTILITY_CSS_PATH = path.join(BASE, 'assets/css/autogenerated-utility.css');

// Simple FNV-1a hash function to generate short unique class names
function getHash(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
  }
  return Math.abs(hash).toString(36).substring(0, 6);
}

function getAllHtmlFiles(dir, files = []) {
  if (!fs.existsSync(dir)) return files;
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    if (entry.name === 'node_modules' || entry.name === '.git' || entry.name === 'dist') continue;
    const fullPath = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      getAllHtmlFiles(fullPath, files);
    } else if (entry.name.endsWith('.html')) {
      files.push(fullPath);
    }
  }
  return files;
}

// Normalize style string for matching
function normalizeStyle(styleStr) {
  return styleStr
    .trim()
    .replace(/\s+/g, ' ')
    .replace(/;?$/, '') // remove trailing semicolon if exists
    .trim() + ';'; // enforce single trailing semicolon
}

// 1. Load existing classes from autogenerated-utility.css
const styleToClassMap = new Map(); // normalizedStyle -> className
const classToStyleMap = new Map(); // className -> normalizedStyle
let existingCssRules = [];

if (fs.existsSync(UTILITY_CSS_PATH)) {
  const content = fs.readFileSync(UTILITY_CSS_PATH, 'utf8');
  // Match rules like: .ref-style-xxxx { background: red; }
  const rulePattern = /^\.([a-zA-Z0-9_-]+)\s*\{\s*([^}]+)\s*\}/gm;
  let match;
  while ((match = rulePattern.exec(content)) !== null) {
    const className = match[1];
    const styleRules = normalizeStyle(match[2]);
    styleToClassMap.set(styleRules, className);
    classToStyleMap.set(className, styleRules);
  }
  console.log(`Loaded ${styleToClassMap.size} existing CSS mappings from autogenerated-utility.css`);
} else {
  console.log('No existing autogenerated-utility.css found. A new one will be created.');
}

// 2. Scan all HTML files
const htmlFiles = getAllHtmlFiles(BASE);
let totalMigratedCount = 0;
let modifiedFilesCount = 0;
const newClassesAdded = [];

for (const filePath of htmlFiles) {
  const relPath = path.relative(BASE, filePath).replace(/\\/g, '/');
  let content = fs.readFileSync(filePath, 'utf8');
  let originalContent = content;
  let fileMigratedCount = 0;

  // Regex to find HTML tags with inline styles: <tag ... style="rules" ...>
  // Handles double/single quotes, handles spaces around style=
  const tagWithStyleRegex = /<([a-zA-Z0-9_-]+)([^>]*?\s+style=(["'])(.*?)\3[^>]*?)>/gi;

  content = content.replace(tagWithStyleRegex, (match, tagName, tagInner, quote, styleContent) => {
    // Skip interactive/JS-driven styles (e.g. display:none or visibility:hidden)
    const normalizedRaw = styleContent.trim().toLowerCase();
    if (
      normalizedRaw === 'display:none' ||
      normalizedRaw === 'display: none' ||
      normalizedRaw === 'display:none;' ||
      normalizedRaw === 'display: none;' ||
      normalizedRaw === 'visibility:hidden' ||
      normalizedRaw === 'visibility: hidden' ||
      normalizedRaw === 'visibility:hidden;' ||
      normalizedRaw === 'visibility: hidden;'
    ) {
      return match; // Keep unchanged
    }

    const normalized = normalizeStyle(styleContent);
    let className = styleToClassMap.get(normalized);

    if (!className) {
      // Generate new class name
      const hash = getHash(normalized);
      className = `ref-style-${hash}`;

      // Collision avoidance (very rare)
      let count = 1;
      while (classToStyleMap.has(className) && classToStyleMap.get(className) !== normalized) {
        className = `ref-style-${hash}${count++}`;
      }

      styleToClassMap.set(normalized, className);
      classToStyleMap.set(className, normalized);
      newClassesAdded.push({ className, rules: normalized });
      console.log(`  [NEW CLASS] Created .${className} for: "${normalized}"`);
    }

    // Replace style="rules" with class="className" inside the tagInner attributes
    let newInner = tagInner;

    // Remove the style attribute
    const styleAttrRegex = new RegExp(`\\s+style=(["'])${escapeRegExp(styleContent)}\\1`, 'gi');
    newInner = newInner.replace(styleAttrRegex, '');

    // Inject class
    const classAttrRegex = /class=(["'])(.*?)\1/i;
    if (classAttrRegex.test(newInner)) {
      // Append class to existing class attribute
      newInner = newInner.replace(classAttrRegex, (m, q, existingClasses) => {
        const classesList = existingClasses.split(/\s+/);
        if (!classesList.includes(className)) {
          return `class=${q}${existingClasses} ${className}${q}`;
        }
        return m;
      });
    } else {
      // Add new class attribute
      newInner = `${newInner} class="${className}"`;
    }

    fileMigratedCount++;
    totalMigratedCount++;
    return `<${tagName}${newInner}>`;
  });

  if (fileMigratedCount > 0 && content !== originalContent) {
    fs.writeFileSync(filePath, content, 'utf8');
    console.log(`✓ Migrated ${fileMigratedCount} style(s) to classes in: ${relPath}`);
    modifiedFilesCount++;
  }
}

// 3. Write new CSS rules to autogenerated-utility.css if any were added
if (newClassesAdded.length > 0) {
  let cssAppendContent = '';
  if (!fs.existsSync(UTILITY_CSS_PATH)) {
    cssAppendContent = `/* ============================================================
   AUTOGENERATED UTILITY CLASSES FOR CSS REFRACTOR MIGRATION
   DO NOT MODIFY DIRECTLY. GENERATED BY migrate-css-postbuild.js
   ============================================================ */\n`;
  } else {
    cssAppendContent = fs.readFileSync(UTILITY_CSS_PATH, 'utf8').trim() + '\n';
  }

  for (const item of newClassesAdded) {
    cssAppendContent += `.${item.className} { ${item.rules} }\n`;
  }

  fs.writeFileSync(UTILITY_CSS_PATH, cssAppendContent, 'utf8');
  console.log(`✓ Added ${newClassesAdded.length} new class rules to autogenerated-utility.css`);
}

console.log(`\n=== CSS UTILITY POSTBUILD COMPLETED ===`);
console.log(`  Modified files: ${modifiedFilesCount}`);
console.log(`  Total inline styles migrated: ${totalMigratedCount}`);
console.log(`=======================================\n`);

// Helper to escape regex special characters
function escapeRegExp(string) {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}